@Service
public class DocumentIngestionService {
    private final VectorStore vectorStore;
    private final DocumentReader documentReader;

    public void ingestDocument(MultipartFile file) {
        List<Document> documents = documentReader.read(file);
        List<Document> chunks = chunkDocuments(documents);
        vectorStore.add(chunks);
    }

    private List<Document> chunkDocuments(List<Document> docs) {
        TokenTextSplitter splitter = new TokenTextSplitter(500, 50);
        return docs.stream()
            .flatMap(doc -> splitter.split(doc).stream())
            .collect(Collectors.toList());
    }
}

@Service
public class RagQueryService {
    private final VectorStore vectorStore;
    private final ChatClient chatClient;

    public String query(String question) {
        // 检索相关文档
        List<Document> similarDocs = vectorStore.similaritySearch(question);

        // 构建增强prompt
        String context = similarDocs.stream()
            .map(Document::getContent)
            .collect(Collectors.joining("\n\n"));

        String prompt = String.format(
            "基于以下信息回答问题:\n%s\n\n问题: %s\n答案:",
            context, question
        );

        return chatClient.prompt(prompt).call().content();
    }
}

@Bean
public FunctionCallback createFileFunction() {
    return FunctionCallback.builder()
        .function("createFile", (args) -> {
            String path = args.getString("path");
            String content = args.getString("content");
            Files.writeString(Path.of(path), content);
            return "File created: " + path;
        })
        .description("Create a file with given path and content")
        .inputSchema("{" +
            "  \"type\": \"object\"," +
            "  \"properties\": {" +
            "    \"path\": {\"type\": \"string\", \"description\": \"File path\"}," +
            "    \"content\": {\"type\": \"string\", \"description\": \"File content\"}" +
            "  }" +
            "}")
        .build();
}

@Service
public class CodeGenerationAgent {
    private final ChatClient chatClient;

    public Project generateProject(String requirement) {
        String systemPrompt = """
            You are an expert Java developer.
            Generate a complete Spring Boot project based on the requirement.
            Think step by step:
            1. Analyze requirements
            2. Design architecture
            3. Generate code files
            4. Verify completeness
            """;

        return chatClient.prompt()
            .system(systemPrompt)
            .user(requirement)
            .functions("createFile", "listFiles", "compileCheck")
            .call()
            .entity(Project.class);
    }
}

