@Service
public class IntentClassifier {
    private final ChatClient chatClient;

    public Intent classify(String userMessage) {
        String prompt = String.format("""
            Classify the following customer message into one of these intents:
            - PRODUCT_INQUIRY: Questions about products
            - ORDER_STATUS: Check order status
            - RETURN_REFUND: Return or refund requests
            - TECHNICAL_SUPPORT: Technical issues
            - COMPLAINT: Complaints
            - OTHER: Other issues

            Message: %s
            Intent:
            """, userMessage);

        String intent = chatClient.prompt(prompt).call().content();
        return Intent.valueOf(intent.trim());
    }
}

@Service
public class ConversationManager {
    private final RedisTemplate<String, ConversationState> redisTemplate;

    public ConversationState getState(String sessionId) {
        String key = "conversation:" + sessionId;
        ConversationState state = redisTemplate.opsForValue().get(key);
        return state != null ? state : new ConversationState();
    }

    public void updateState(String sessionId, ConversationState state) {
        redisTemplate.opsForValue().set(
            "conversation:" + sessionId, 
            state, 
            30, 
            TimeUnit.MINUTES
        );
    }
}

